def gen(rng, size):
    n = max(1, min(size, 10000))
    positions = list(range(0, n + 1))
    rng.shuffle(positions)
    k = rng.randint(1, len(positions))
    chosen = positions[:k]
    left = []
    right = []
    for p in chosen:
        if rng.random() < 0.5:
            left.append(p)
        else:
            right.append(p)
    if not left and not right:
        right.append(chosen[0])
    return [n, left, right]

